#!/bin/bash
set -e

source scripts/env/app/pds.sh
source scripts/env/app/sds.sh
source scripts/env/app/provider.sh

ENV_FILE=".env"

PDS_URL=$(get_pds_url "$env")
SDS_URL=$(get_sds_url "$env")
PROVIDER_URL=$(get_provider_url "$env")

cat > "$ENV_FILE" <<EOF
# This file was generated by 'make env-$env'.

PDS_URL=$PDS_URL
PDS_API_TOKEN=
PDS_API_SECRET=
PDS_API_KID=

PROVIDER_URL=$PROVIDER_URL

SDS_URL=$SDS_URL
SDS_API_TOKEN=

CDG_DEBUG=false
EOF

echo "$ENV_FILE for $env written."
